self.addEventListener("push",t=>{if(t.data)try{let i=t.data.json(),n={body:i.body,icon:i.icon||"/icon-192x192.png",badge:i.badge||"/icon-192x192.png",data:{url:i.url||"/"}};t.waitUntil(self.registration.showNotification(i.title,n))}catch(n){console.error("Error parseando push data:",n);let i=t.data.text();t.waitUntil(self.registration.showNotification("Alerta de Alumin\xe9GO",{body:i,icon:"/icon-192x192.png",badge:"/icon-192x192.png"}))}}),self.addEventListener("notificationclick",t=>{t.notification.close();let i=t.notification.data?.url||"/";t.waitUntil(self.clients.matchAll({type:"window",includeUncontrolled:!0}).then(t=>{for(let n=0;n<t.length;n++){let e=t[n];if(e.url===i&&"focus"in e)return e.focus()}if(self.clients.openWindow)return self.clients.openWindow(i)}))});